  1→import type { Block, ImportJob } from "@chat-exporter/shared";
  2→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  3→import { ErrorBoundary } from "@/components/error-boundary";
  4→import { AdjustmentModeGuide } from "@/components/format-workspace/adjustment-mode-guide";
  5→import { AdjustmentPopover } from "@/components/format-workspace/adjustment-popover";
  6→import { CompletedToolbar } from "@/components/format-workspace/completed-toolbar";
  7→import { DeleteMessageDialog } from "@/components/format-workspace/delete-message-dialog";
  8→import {
  9→  formatMarkdownLinesLabel,
 10→  formatMessageBlockLabel,
 11→  getImportStageLabel,
 12→  miscLabels,
 13→} from "@/components/format-workspace/labels";
 14→import { LoadingStateBlock } from "@/components/format-workspace/loading-state-block";
 15→import { copyMessageToClipboard } from "@/components/format-workspace/message-clipboard";
 16→import {
 17→  applyMarkdownRules,
 18→  buildReaderEffectsMap,
 19→} from "@/components/format-workspace/rule-engine";
 20→import { SaveIndicator } from "@/components/format-workspace/save-indicator";
 21→import { StatusHeader } from "@/components/format-workspace/status-header";
 22→import {
 23→  type AdjustmentSelection,
 24→  adjustableViews,
 25→  type EditMode,
 26→  type ViewMode,
 27→} from "@/components/format-workspace/types";
 28→import { UndoToast } from "@/components/format-workspace/undo-toast";
 29→import { useAdjustmentPopover } from "@/components/format-workspace/use-adjustment-popover";
 30→import { useAdjustmentSession } from "@/components/format-workspace/use-adjustment-session";
 31→import { useAutoSnapshot } from "@/components/format-workspace/use-auto-snapshot";
 32→import { useDeletionToast } from "@/components/format-workspace/use-deletion-toast";
 33→import { useFormatRules } from "@/components/format-workspace/use-format-rules";
 34→import { useMessageDeletion } from "@/components/format-workspace/use-message-deletion";
 35→import { useMessageEdits } from "@/components/format-workspace/use-message-edits";
 36→import { useResolvedConversation } from "@/components/format-workspace/use-resolved-conversation";
 37→import { useSnapshots } from "@/components/format-workspace/use-snapshots";
 38→import { VersionsModal } from "@/components/format-workspace/versions-modal";
 39→import { clientFormatRegistry } from "@/lib/format-plugins";
 40→
 41→type ActiveStage = {
 42→  detail: string;
 43→  label: string;
 44→} | null;
 45→
 46→type FormatWorkspaceProps = {
 47→  activeStage: ActiveStage;
 48→  elapsedTime: string;
 49→  job: ImportJob;
 50→  view: ViewMode;
 51→  onViewChange: (view: ViewMode) => void;
 52→};
 53→
 54→function _describeSelectionLabel(selection: AdjustmentSelection) {
 55→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 56→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 57→  }
 58→
 59→  return formatMessageBlockLabel(
 60→    selection.messageRole,
 61→    selection.messageIndex + 1,
 62→    selection.blockType,
 63→  );
 64→}
 65→
 66→function downloadBlob(content: string, mimeType: string, filename: string) {
 67→  const blob = new Blob([content], { type: mimeType });
 68→  const url = URL.createObjectURL(blob);
 69→  const a = document.createElement("a");
 70→  a.href = url;
 71→  a.download = filename;
 72→  document.body.appendChild(a);
 73→  a.click();
 74→  document.body.removeChild(a);
 75→  setTimeout(() => URL.revokeObjectURL(url), 100);
 76→}
 77→
 78→export function FormatWorkspace({
 79→  activeStage,
 80→  elapsedTime,
 81→  job,
 82→  view,
 83→  onViewChange,
 84→}: FormatWorkspaceProps) {
 85→  const isAdjustableView = adjustableViews.has(view);
 86→
 87→  const session = useAdjustmentSession(view, job.id);
 88→  const rules = useFormatRules(view, job.id);
 89→  const snapshots = useSnapshots(job.id);
 90→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 91→  const resolvedMessages = useResolvedConversation(
 92→    job.conversation,
 93→    messageEdits.editedMessagesMap,
 94→  );
 95→  const autoSnapshot = useAutoSnapshot({
 96→    activeSnapshot: snapshots.activeSnapshot,
 97→    create: snapshots.create,
 98→    activate: snapshots.activate,
 99→  });
100→  const deletion = useMessageDeletion(job.id);
101→  const deletionToast = useDeletionToast();
102→  const [editMode, setEditMode] = useState<EditMode>("view");
103→
104→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
105→  const handleEditModeChange = useCallback(
106→    (mode: EditMode) => {
107→      if (mode === "edit" && session.adjustModeEnabled) {
108→        session.toggleAdjustMode();
109→      }
110→      setEditMode(mode);
111→    },
112→    [session],
113→  );
114→
115→  const handleToggleAdjustMode = useCallback(() => {
116→    if (!session.adjustModeEnabled && editMode === "edit") {
117→      setEditMode("view");
118→    }
119→    session.toggleAdjustMode();
120→  }, [session, editMode]);
121→
122→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
123→
124→  // beforeunload warning when unsaved edits exist.
125→  // hasPendingEdits covers both debounce timers that haven't fired yet and
126→  // in-flight HTTP mutations, preventing data loss during the 500 ms debounce
127→  // window where isSaving alone would still be false.
128→  useEffect(() => {
129→    if (!messageEdits.hasPendingEdits) return;
130→    const handler = (e: BeforeUnloadEvent) => {
131→      e.preventDefault();
132→    };
133→    window.addEventListener("beforeunload", handler);
134→    return () => window.removeEventListener("beforeunload", handler);
135→  }, [messageEdits.hasPendingEdits]);
136→
137→  const handleBlocksChange = useCallback(
138→    (messageId: string, blocks: Block[]) => {
139→      void autoSnapshot.ensureSnapshot().then((ready) => {
140→        if (ready) {
141→          messageEdits.saveEdit(messageId, blocks);
142→        }
143→      });
144→    },
145→    [autoSnapshot, messageEdits],
146→  );
147→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
148→  const [deleteDialog, setDeleteDialog] = useState<{
149→    messageId: string;
150→    isRound: boolean;
151→    preview: string;
152→  } | null>(null);
153→  const popover = useAdjustmentPopover();
154→
155→  const handleDeleteMessage = useCallback(
156→    (messageId: string) => {
157→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
158→      const preview =
159→        msg?.blocks
160→          .map((b) => ("text" in b ? b.text : b.type))
161→          .join(" ")
162→          .slice(0, 200) ?? messageId;
163→      setDeleteDialog({ messageId, isRound: false, preview });
164→    },
165→    [job.conversation?.messages],
166→  );
167→
168→  const handleDeleteRound = useCallback(
169→    (messageId: string) => {
170→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
171→      const preview =
172→        msg?.blocks
173→          .map((b) => ("text" in b ? b.text : b.type))
174→          .join(" ")
175→          .slice(0, 200) ?? messageId;
176→      setDeleteDialog({ messageId, isRound: true, preview });
177→    },
178→    [job.conversation?.messages],
179→  );
180→
181→  const handleConfirmDelete = useCallback(
182→    async (reason?: string) => {
183→      if (!deleteDialog) return;
184→      const { messageId, isRound } = deleteDialog;
185→      setDeleteDialog(null);
186→      if (isRound) {
187→        const result = await deletion.deleteRound(messageId, reason);
188→        deletionToast.showDeletedToast(messageId, true, result.length);
189→      } else {
190→        await deletion.deleteMessage(messageId, reason);
191→        deletionToast.showDeletedToast(messageId, false);
192→      }
193→    },
194→    [deleteDialog, deletion, deletionToast],
195→  );
196→
197→  const handleUndoDelete = useCallback(async () => {
198→    if (!deletionToast.toast) return;
199→    await deletion.restoreMessage(deletionToast.toast.messageId);
200→    deletionToast.dismissToast();
201→  }, [deletion, deletionToast]);
202→
203→  const mergedRef = useCallback(
204→    (node: HTMLElement | null) => {
205→      (
206→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
207→      ).current = node;
208→      (
209→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
210→      ).current = node;
211→    },
212→    [session.sectionRef, popover.containerRef],
213→  );
214→
215→  const artifact =
216→    view === "reader" || view === "html-export"
217→      ? ""
218→      : (job.artifacts?.[view] ?? "Artefakt ist noch nicht verfügbar.");
219→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
220→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
221→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
222→  const displayedMarkdown = useMemo(() => {
223→    if (view !== "markdown") return artifact;
224→    try {
225→      return applyMarkdownRules(artifact, rules.activeRules);
226→    } catch {
227→      return artifact;
228→    }
229→  }, [artifact, rules.activeRules, view]);
230→
231→  const resolvedConversation = useMemo(() => {
232→    if (!job.conversation) return undefined;
233→    return {
234→      ...job.conversation,
235→      messages: resolvedMessages.map((rm) => ({
236→        id: rm.id,
237→        role: rm.role,
238→        blocks: rm.blocks,
239→      })),
240→    };
241→  }, [job.conversation, resolvedMessages]);
242→
243→  const readerEffectsMap = useMemo(
244→    () =>
245→      (view === "reader" || view === "html-export") && resolvedConversation
246→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
247→        : new Map(),
248→    [rules.activeRules, resolvedConversation, view],
249→  );
250→
251→  const handleCopyMessage = useCallback(
252→    (messageId: string) => {
253→      const msg = resolvedConversation?.messages.find(
254→        (m) => m.id === messageId,
255→      );
256→      if (!msg) return;
257→      void copyMessageToClipboard(msg, view, msg.blocks);
258→    },
259→    [resolvedConversation, view],
260→  );
261→
262→  const [copySuccess, setCopySuccess] = useState(false);
263→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
264→
265→  const handleCopyAll = useMemo(() => {
266→    const plugin = clientFormatRegistry.get(view);
267→    if (!plugin) return undefined;
268→
269→    const doCopy = async (content: string, isHtml: boolean) => {
270→      try {
271→        if (isHtml) {
272→          const blob = new Blob([content], { type: "text/html" });
273→          const plainBlob = new Blob([content], { type: "text/plain" });
274→          await navigator.clipboard.write([
275→            new ClipboardItem({
276→              "text/html": blob,
277→              "text/plain": plainBlob,
278→            }),
279→          ]);
280→        } else {
281→          await navigator.clipboard.writeText(content);
282→        }
283→        clearTimeout(copyTimeoutRef.current);
284→        setCopySuccess(true);
285→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
286→      } catch {
287→        // Fallback: silently fail
288→      }
289→    };
290→
291→    // Formats with conversation-based export (reader, html-export)
292→    if (plugin.prepareConversationExport && resolvedConversation) {
293→      return () => {
294→        const html = plugin.prepareConversationExport!(
295→          resolvedConversation,
296→          readerEffectsMap,
297→          resolvedConversation.title ?? `export-${job.id}`,
298→        );
299→        void doCopy(html, true);
300→      };
301→    }
302→
303→    // Markdown: displayedMarkdown already has rules applied
304→    if (view === "markdown") {
305→      return () => {
306→        void doCopy(displayedMarkdown, false);
307→      };
308→    }
309→
310→    // Others: raw artifact
311→    if (artifact) {
312→      return () => {
313→        void doCopy(artifact, false);
314→      };
315→    }
316→    return undefined;
317→  }, [
318→    view,
319→    displayedMarkdown,
320→    job.id,
321→    resolvedConversation,
322→    readerEffectsMap,
323→    artifact,
324→  ]);
325→
326→  const handleDownload = useMemo(() => {
327→    const plugin = clientFormatRegistry.get(view);
328→    if (!plugin) return undefined;
329→
330→    // Formats with conversation-based export (reader, html-export)
331→    if (plugin.prepareConversationExport && resolvedConversation) {
332→      return () => {
333→        const html = plugin.prepareConversationExport!(
334→          resolvedConversation,
335→          readerEffectsMap,
336→          resolvedConversation.title ?? `export-${job.id}`,
337→        );
338→        downloadBlob(
339→          html,
340→          plugin.descriptor.exportMimeType,
341→          `export-${job.id}${plugin.descriptor.exportExtension}`,
342→        );
343→      };
344→    }
345→
346→    // For all other formats: use prepareDownload if available, else raw content
347→    const content = view === "markdown" ? displayedMarkdown : artifact;
348→    if (!content) return undefined;
349→
350→    return () => {
351→      const finalContent =
352→        plugin.prepareDownload?.(content, rules.activeRules) ?? content;
353→      downloadBlob(
354→        finalContent,
355→        plugin.descriptor.exportMimeType,
356→        `export-${job.id}${plugin.descriptor.exportExtension}`,
357→      );
358→    };
359→  }, [
360→    view,
361→    displayedMarkdown,
362→    job.id,
363→    resolvedConversation,
364→    readerEffectsMap,
365→    artifact,
366→    rules.activeRules,
367→  ]);
368→  const showPopover =
369→    session.adjustModeEnabled &&
370→    Boolean(session.activeSelection) &&
371→    Boolean(session.activeAnchor);
372→
373→  const popoverCallbacksRef = useRef({
374→    handleDiscardSession: session.handleDiscardSession,
375→    activeSessionDetail: session.activeSessionDetail,
376→    handleRejectLastChange: rules.handleRejectLastChange,
377→    setReplyVisible: session.setReplyVisible,
378→  });
379→  popoverCallbacksRef.current = {
380→    handleDiscardSession: session.handleDiscardSession,
381→    activeSessionDetail: session.activeSessionDetail,
382→    handleRejectLastChange: rules.handleRejectLastChange,
383→    setReplyVisible: session.setReplyVisible,
384→  };
385→
386→  const handlePopoverClose = useCallback(() => {
387→    popoverCallbacksRef.current.handleDiscardSession();
388→  }, []);
389→
390→  const handleRejectLastChange = useCallback(() => {
391→    const {
392→      activeSessionDetail,
393→      handleRejectLastChange: reject,
394→      setReplyVisible,
395→    } = popoverCallbacksRef.current;
396→    if (activeSessionDetail) {
397→      void reject(activeSessionDetail).then((success) => {
398→        if (success) setReplyVisible(false);
399→      });
400→    }
401→  }, []);
402→
403→  const sessionError =
404→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
405→
406→  const viewErrorFallback = (_error: Error, reset: () => void) => (
407→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
408→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
409→      <button
410→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
411→        type="button"
412→        onClick={reset}
413→      >
414→        {miscLabels.retryButton}
415→      </button>
416→    </div>
417→  );
418→
419→  return (
420→    <section
421→      ref={mergedRef}
422→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
423→    >
424→      <StatusHeader
425→        activeStage={activeStage}
426→        elapsedTime={elapsedTime}
427→        job={job}
428→      />
429→
430→      {job.warnings.length > 0 ? (
431→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
432→          {job.warnings[0]}
433→        </div>
434→      ) : null}
435→
436→      {job.status === "failed" ? (
437→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
438→          <p className="font-medium">{miscLabels.importFailed}</p>
439→          {job.errorStage && job.errorStage !== "done" && (
440→            <p className="text-sm mt-1">
441→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
442→            </p>
443→          )}
444→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
445→        </div>
446→      ) : job.status === "queued" || job.status === "running" ? (
447→        <LoadingStateBlock stageDetail={activeStage?.detail} />
448→      ) : (
449→        <div className="space-y-4">
450→          <CompletedToolbar
451→            adjustModeEnabled={session.adjustModeEnabled}
452→            copySuccess={copySuccess}
453→            editMode={editMode}
454→            isAdjustableView={isAdjustableView}
455→            rules={rules}
456→            view={view}
457→            onCopyAll={handleCopyAll}
458→            onDownloadMarkdown={handleDownload}
459→            onEditModeChange={handleEditModeChange}
460→            onToggleAdjustMode={handleToggleAdjustMode}
461→            onViewChange={onViewChange}
462→            deletionsCount={deletion.deletionsCount}
463→            showDeleted={deletion.showDeleted}
464→            snapshotCount={snapshots.snapshots.length}
465→            onVersionsClick={() => setVersionsModalOpen(true)}
466→            onToggleShowDeleted={() =>
467→              deletion.setShowDeleted(!deletion.showDeleted)
468→            }
469→          />
470→
471→          {sessionError && !session.adjustModeEnabled ? (
472→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
473→              {sessionError}
474→            </div>
475→          ) : null}
476→
477→          <ErrorBoundary fallback={viewErrorFallback}>
478→            {(() => {
479→              const plugin = clientFormatRegistry.get(view);
480→              if (!plugin) {
481→                return (
482→                  <div className="text-sm text-muted-foreground">
483→                    Format nicht verfügbar
484→                  </div>
485→                );
486→              }
487→              const { ViewComponent } = plugin;
488→              const viewElement = (
489→                <ViewComponent
490→                  activeRules={rules.activeRules}
491→                  conversation={resolvedConversation}
492→                  adjustModeEnabled={session.adjustModeEnabled}
493→                  editMode={editMode === "edit"}
494→                  effectsMap={readerEffectsMap}
495→                  highlightedRuleId={rules.hoveredRuleId}
496→                  selectedBlock={
497→                    view === "reader" ? session.activeSelection : null
498→                  }
499→                  onSelectBlock={session.handleSelectionChange}
500→                  deletedMessageIds={deletion.deletedMessageIds}
501→                  showDeleted={deletion.showDeleted}
502→                  onBlocksChange={handleBlocksChange}
503→                  onCopyMessage={handleCopyMessage}
504→                  onDeleteMessage={handleDeleteMessage}
505→                  onDeleteRound={handleDeleteRound}
506→                  onRestoreMessage={deletion.restoreMessage}
507→                  content={
508→                    view === "markdown" ? displayedMarkdown : artifact
509→                  }
510→                  selectedRange={session.activeSelection}
511→                  onSelectLines={session.handleSelectionChange}
512→                  rules={rules.activeRules}
513→                />
514→              );
515→              if (view === "reader") {
516→                return (
517→                  <div className="space-y-2">
518→                    <div className="flex justify-end">
519→                      <SaveIndicator
520→                        isSaving={messageEdits.isSaving}
521→                        hasEdits={hasEdits}
522→                      />
523→                    </div>
524→                    {viewElement}
525→                  </div>
526→                );
527→              }
528→              return viewElement;
529→            })()}
530→          </ErrorBoundary>
531→
532→          {session.showGuide ? (
533→            <AdjustmentModeGuide
534→              view={view}
535→              onDismiss={() => session.setGuideDismissed(true)}
536→            />
537→          ) : null}
538→
539→          <ErrorBoundary
540→            fallback={
541→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
542→                {miscLabels.adjustmentLoadError}
543→              </div>
544→            }
545→          >
546→            <AdjustmentPopover
547→              anchor={session.activeAnchor ?? null}
548→              containerRef={session.sectionRef}
549→              draftMessage={session.activeDraftMessage}
550→              error={session.activeSessionError}
551→              isLoading={session.activeSessionLoading || session.isDiscarding}
552→              isSubmitting={session.isSubmitting}
553→              open={
554→                showPopover &&
555→                Boolean(session.activeSelection) &&
556→                Boolean(session.activeAnchor)
557→              }
558→              sessionDetail={session.activeSessionDetail}
559→              showReply={session.replyVisible}
560→              view={view}
561→              onClose={handlePopoverClose}
562→              onDraftMessageChange={session.handleDraftMessageChange}
563→              onRejectLastChange={handleRejectLastChange}
564→              onSubmitMessage={session.handleSubmitMessage}
565→            />
566→          </ErrorBoundary>
567→        </div>
568→      )}
569→
570→      {deleteDialog && (
571→        <DeleteMessageDialog
572→          messagePreview={deleteDialog.preview}
573→          isRound={deleteDialog.isRound}
574→          onConfirm={(reason) => {
575→            void handleConfirmDelete(reason);
576→          }}
577→          onCancel={() => setDeleteDialog(null)}
578→        />
579→      )}
580→
581→      {deletionToast.toast && (
582→        <UndoToast
583→          message={deletionToast.toast.message}
584→          onUndo={() => {
585→            void handleUndoDelete();
586→          }}
587→          onDismiss={deletionToast.dismissToast}
588→        />
589→      )}
590→
591→      <VersionsModal
592→        open={versionsModalOpen}
593→        onOpenChange={setVersionsModalOpen}
594→        snapshots={snapshots.snapshots}
595→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
596→        onActivate={(snapshotId) => {
597→          void snapshots.activate(snapshotId);
598→        }}
599→        onDeactivate={() => {
600→          void snapshots.deactivate();
601→        }}
602→        onCreate={(label) => {
603→          void snapshots.create(label);
604→        }}
605→        onRename={(snapshotId, label) => {
606→          void snapshots.rename(snapshotId, label);
607→        }}
608→        onDelete={(snapshotId) => {
609→          void snapshots.delete(snapshotId);
610→        }}
611→      />
612→    </section>
613→  );
614→}
