 1→type SaveIndicatorProps = {
 2→  isSaving: boolean;
 3→  hasEdits: boolean;
 4→};
 5→
 6→export function SaveIndicator({ isSaving, hasEdits }: SaveIndicatorProps) {
 7→  if (!hasEdits) return null;
 8→
 9→  return (
10→    <span className="text-xs text-muted-foreground">
11→      {isSaving ? "Speichert..." : "Gespeichert \u2713"}
12→    </span>
13→  );
14→}
