 1→import type { ImportJob } from "@chat-exporter/shared";
 2→import { Clock3, LoaderCircle } from "lucide-react";
 3→
 4→import { getJobStatusLabel } from "@/components/format-workspace/labels";
 5→import { Badge } from "@/components/ui/badge";
 6→
 7→type ActiveStage = {
 8→  detail: string;
 9→  label: string;
10→} | null;
11→
12→type StatusHeaderProps = {
13→  activeStage: ActiveStage;
14→  elapsedTime: string;
15→  job: ImportJob;
16→};
17→
18→export function StatusHeader({
19→  activeStage,
20→  elapsedTime,
21→  job,
22→}: StatusHeaderProps) {
23→  return (
24→    <div className="flex flex-wrap items-center gap-3">
25→      <Badge variant={job.status === "completed" ? "default" : "outline"}>
26→        {getJobStatusLabel(job.status)}
27→      </Badge>
28→      {job.summary ? (
29→        <p className="text-sm text-muted-foreground">
