 17→/**
 18→ * Read the DOM content of the editable element and construct a new Block
 19→ * that matches the original block's type, preserving type-specific fields
 20→ * (e.g. heading level, code language, list ordered flag).
 21→ */
 22→function readBlockFromDom(element: HTMLElement, original: Block): Block {
 23→  switch (original.type) {
 24→    case "paragraph":
 25→      return { type: "paragraph", text: element.textContent ?? "" };
 26→
 27→    case "heading":
 28→      return {
 29→        type: "heading",
 30→        level: original.level,
 31→        text: element.textContent ?? "",
 32→      };
 33→
 34→    case "quote":
 35→      return { type: "quote", text: element.textContent ?? "" };
 36→
 37→    case "code": {
 38→      const codeEl = element.querySelector("pre code");
 39→      return {
 40→        type: "code",
 41→        language: original.language,
 42→        text: codeEl ? (codeEl.textContent ?? "") : (element.textContent ?? ""),
 43→      };
 44→    }
 45→
 46→    case "list": {
 47→      const listItems = element.querySelectorAll("li");
 48→      const items = Array.from(listItems).map((li) => li.textContent ?? "");
 49→      return {
 50→        type: "list",
 51→        ordered: original.ordered,
 52→        items: items.length > 0 ? items : [element.textContent ?? ""],
 53→      };
 54→    }
 55→
 56→    case "table": {
 57→      const thElements = element.querySelectorAll("th");
 58→      const headers = Array.from(thElements).map((th) => th.textContent ?? "");
 59→
 60→      const bodyRows = element.querySelectorAll("tbody tr");
 61→      const rows = Array.from(bodyRows).map((tr) => {
 62→        const cells = tr.querySelectorAll("td");
 63→        return Array.from(cells).map((td) => td.textContent ?? "");
 64→      });
 65→
 66→      return { type: "table", headers, rows };
 67→    }
 68→
 69→    default:
 70→      return original;
 71→  }
 72→}
