445→    if (!conversation?.messages) return [];
446→    if (!deletedMessageIds?.size) return conversation.messages;
447→    if (showDeleted) return conversation.messages;
448→    return conversation.messages.filter((m) => !deletedMessageIds.has(m.id));
449→  }, [conversation?.messages, deletedMessageIds, showDeleted]);
450→
451→  // Tracks the latest in-progress blocks per message so that consecutive edits
452→  // within the same debounce window build on top of each other rather than on
453→  // stale props (which would cause earlier edits to be overwritten).
454→  const pendingBlocksRef = useRef<Map<string, Block[]>>(new Map());
455→
456→  // When the conversation prop updates (i.e. the parent has persisted the edit
457→  // and passed the new data back down), clear any pending entries whose blocks
458→  // now match the incoming props — they are no longer "in-flight".
459→  useEffect(() => {
460→    if (!conversation) return;
461→    const pending = pendingBlocksRef.current;
462→    for (const [messageId] of pending) {
463→      const message = conversation.messages.find((m) => m.id === messageId);
464→      if (!message) {
465→        pending.delete(messageId);
466→        continue;
467→      }
468→      // If the prop blocks now reflect our last pending write, the save has
469→      // been acknowledged — remove the entry so the next edit starts fresh.
470→      const pendingBlocks = pending.get(messageId);
471→      if (
472→        pendingBlocks &&
473→        pendingBlocks.length === message.blocks.length &&
474→        pendingBlocks.every((b, i) => b === message.blocks[i])
475→      ) {
476→        pending.delete(messageId);
477→      }
478→    }
479→  }, [conversation]);
480→
481→  const highlightedBlocks = useMemo(() => {
482→    if (!highlightedRuleId || !conversation) {
483→      return new Set<string>();
484→    }
485→
486→    const rule = activeRules.find(
487→      (r) => r.id === highlightedRuleId && r.status === "active",
488→    );
489→
490→    if (!rule) {
491→      return new Set<string>();
492→    }
493→
494→    const matches = getBlocksMatchingRule(rule, conversation);
495→    return new Set(matches.map((m) => `${m.messageId}:${m.blockIndex}`));
496→  }, [highlightedRuleId, activeRules, conversation]);
