 22→// ---------------------------------------------------------------------------
 23→// Pure utility: extract text from any block type
 24→// ---------------------------------------------------------------------------
 25→
 26→export function getBlockText(block: Block): string {
 27→  switch (block.type) {
 28→    case "paragraph":
 29→    case "heading":
 30→    case "quote":
 31→    case "code":
 32→      return block.text;
 33→    case "list":
 34→      return block.items.join("\n");
 35→    case "table": {
 36→      const headerLine = block.headers.join(" | ");
 37→      const rows = block.rows.map((row) => row.join(" | ")).join("\n");
 38→      return rows ? `${headerLine}\n${rows}` : headerLine;
 39→    }
 40→  }
 41→}
 42→
 43→// ---------------------------------------------------------------------------
 44→// Pure utility: convert a block to a different type
 45→// ---------------------------------------------------------------------------
 46→
 47→export type ConvertibleBlockType = "paragraph" | "heading" | "quote" | "list";
 48→
 49→export function convertBlockType(
 50→  block: Block,
 51→  targetType: ConvertibleBlockType,
 52→): Block {
 53→  const text = getBlockText(block);
 54→  switch (targetType) {
 55→    case "paragraph":
 56→      return { type: "paragraph", text };
 57→    case "heading":
 58→      return { type: "heading", level: 2, text };
 59→    case "quote":
 60→      return { type: "quote", text };
 61→    case "list":
 62→      return { type: "list", ordered: false, items: [text] };
 63→  }
 64→}
